SELECT 
FROM xxl_job_alarm_rule t


        AND t.job_group = #{jobGroup}


        AND t.job_id = #{jobId}


        AND t.alarm_event = #{alarmEvent}


        AND t.enabled = #{enabled}


ORDER BY t.id DESC
LIMIT #{offset}, #{pagesize}

SELECT count(1)
FROM xxl_job_alarm_rule t


        AND t.job_group = #{jobGroup}


        AND t.job_id = #{jobId}


        AND t.alarm_event = #{alarmEvent}


        AND t.enabled = #{enabled}

SELECT 
FROM xxl_job_alarm_rule t
WHERE t.id = #{id}
